import{_ as e,o as l,c as a,al as n}from"./chunks/framework.GnR-YWkE.js";const f=JSON.parse('{"title":"CLI 工具概覽","description":"","frontmatter":{},"headers":[],"relativePath":"zh-HK/cli/index.md","filePath":"zh-HK/cli/index.md","lastUpdated":1771838368000}'),d={name:"zh-HK/cli/index.md"};function r(i,t,s,o,c,h){return l(),a("div",null,[...t[0]||(t[0]=[n('<h1 id="cli-工具概覽" tabindex="-1">CLI 工具概覽 <a class="header-anchor" href="#cli-工具概覽" aria-label="Permalink to “CLI 工具概覽”">​</a></h1><p>QuecPanel CLI (<code>@quec/oem-cli</code>) 是專為 QuecPanel 開發者打造的一站式命令行工具。它不僅簡化了項目的初始化流程，還提供了從物模型生成到多語言管理的全鏈路支持。</p><h2 id="為什麼使用-cli" tabindex="-1">為什麼使用 CLI？ <a class="header-anchor" href="#為什麼使用-cli" aria-label="Permalink to “為什麼使用 CLI？”">​</a></h2><ul><li><strong>快速啟動</strong>：通過標準化模板一鍵創建工程，無需手動搭建環境。</li><li><strong>自動化構建</strong>：集成了 Webpack 等構建工具，簡化打包發布流程。</li><li><strong>代碼生成</strong>：自動從物模型 JSON 生成 TypeScript 類型定義，減少重複勞動。</li><li><strong>多語言支持</strong>：一鍵掃描並導出多語言配置，提升國際化開發效率。</li></ul><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to “核心功能”">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">功能模塊</th><th style="text-align:left;">對應命令</th><th style="text-align:left;">說明</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>工程管理</strong></td><td style="text-align:left;"><a href="./commands.html#createpanel"><code>createPanel</code></a></td><td style="text-align:left;">創建新的面板項目</td></tr><tr><td style="text-align:left;"><strong>構建發布</strong></td><td style="text-align:left;"><a href="./commands.html#buildpanel"><code>buildPanel</code></a></td><td style="text-align:left;">生成 Android/iOS 離線發布包</td></tr><tr><td style="text-align:left;"><strong>物模型</strong></td><td style="text-align:left;"><a href="./commands.html#gentslmodel"><code>genTslModel</code></a></td><td style="text-align:left;">生成 TSL 類型定義與配置</td></tr><tr><td style="text-align:left;"><strong>多語言</strong></td><td style="text-align:left;"><a href="./commands.html#geni18n"><code>genI18n</code></a></td><td style="text-align:left;">導出多語言 Excel 文件</td></tr></tbody></table><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to “下一步”">​</a></h2><ul><li><a href="./install.html">安裝 CLI</a> - 了解如何安裝和配置開發環境。</li><li><a href="./commands.html">命令行參考</a> - 查看所有命令的詳細參數和用法。</li></ul>',8)])])}const m=e(d,[["render",r]]);export{f as __pageData,m as default};
